import { DynamoDBClient, PutItemCommand, GetItemCommand, DeleteItemCommand, UpdateItemCommand } from '@aws-sdk/client-dynamodb';
import { Pool } from 'pg';

// DynamoDB Client
const dynamoClient = new DynamoDBClient({ region: process.env.AWS_REGION || 'us-east-1' });
const CONNECTIONS_TABLE = process.env.CONNECTIONS_TABLE!;

// PostgreSQL Client (reuse connection pool)
let pgPool: Pool | null = null;

function getPgPool(): Pool {
  if (!pgPool) {
    pgPool = new Pool({
      connectionString: process.env.DATABASE_URL,
      max: 2, // Lambda concurrency limit
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000
    });
  }
  return pgPool;
}

// ===== DynamoDB Operations (WebSocket Connections) =====

export interface WebSocketConnection {
  connectionId: string;
  agentId?: string;
  conversationId?: string;
  connectedAt: number;
  lastActiveAt: number;
  metadata?: Record<string, any>;
  ttl: number; // Auto-expire after 2 hours
}

export async function saveConnection(connection: WebSocketConnection): Promise<void> {
  try {
    await dynamoClient.send(new PutItemCommand({
      TableName: CONNECTIONS_TABLE,
      Item: {
        connectionId: { S: connection.connectionId },
        agentId: connection.agentId ? { S: connection.agentId } : { NULL: true },
        conversationId: connection.conversationId ? { S: connection.conversationId } : { NULL: true },
        connectedAt: { N: connection.connectedAt.toString() },
        lastActiveAt: { N: connection.lastActiveAt.toString() },
        metadata: connection.metadata ? { S: JSON.stringify(connection.metadata) } : { NULL: true },
        ttl: { N: connection.ttl.toString() }
      }
    }));
    console.log(`[DynamoDB] Connection saved: ${connection.connectionId}`);
  } catch (error) {
    console.error('[DynamoDB] Error saving connection:', error);
    throw error;
  }
}

export async function getConnection(connectionId: string): Promise<WebSocketConnection | null> {
  try {
    const result = await dynamoClient.send(new GetItemCommand({
      TableName: CONNECTIONS_TABLE,
      Key: {
        connectionId: { S: connectionId }
      }
    }));

    if (!result.Item) {
      return null;
    }

    return {
      connectionId: result.Item.connectionId.S!,
      agentId: result.Item.agentId?.S,
      conversationId: result.Item.conversationId?.S,
      connectedAt: parseInt(result.Item.connectedAt.N!),
      lastActiveAt: parseInt(result.Item.lastActiveAt.N!),
      metadata: result.Item.metadata?.S ? JSON.parse(result.Item.metadata.S) : undefined,
      ttl: parseInt(result.Item.ttl.N!)
    };
  } catch (error) {
    console.error('[DynamoDB] Error getting connection:', error);
    return null;
  }
}

export async function updateConnection(connectionId: string, updates: Partial<WebSocketConnection>): Promise<void> {
  const updateExpression: string[] = [];
  const expressionAttributeValues: Record<string, any> = {};

  if (updates.agentId !== undefined) {
    updateExpression.push('agentId = :agentId');
    expressionAttributeValues[':agentId'] = { S: updates.agentId };
  }

  if (updates.conversationId !== undefined) {
    updateExpression.push('conversationId = :conversationId');
    expressionAttributeValues[':conversationId'] = { S: updates.conversationId };
  }

  if (updates.lastActiveAt !== undefined) {
    updateExpression.push('lastActiveAt = :lastActiveAt');
    expressionAttributeValues[':lastActiveAt'] = { N: updates.lastActiveAt.toString() };
  }

  if (updateExpression.length === 0) {
    return;
  }

  try {
    await dynamoClient.send(new UpdateItemCommand({
      TableName: CONNECTIONS_TABLE,
      Key: {
        connectionId: { S: connectionId }
      },
      UpdateExpression: `SET ${updateExpression.join(', ')}`,
      ExpressionAttributeValues: expressionAttributeValues
    }));
    console.log(`[DynamoDB] Connection updated: ${connectionId}`);
  } catch (error) {
    console.error('[DynamoDB] Error updating connection:', error);
    throw error;
  }
}

export async function deleteConnection(connectionId: string): Promise<void> {
  try {
    await dynamoClient.send(new DeleteItemCommand({
      TableName: CONNECTIONS_TABLE,
      Key: {
        connectionId: { S: connectionId }
      }
    }));
    console.log(`[DynamoDB] Connection deleted: ${connectionId}`);
  } catch (error) {
    console.error('[DynamoDB] Error deleting connection:', error);
    throw error;
  }
}

// ===== PostgreSQL Operations (Conversations & Transcripts) =====

export interface Conversation {
  id: string;
  agent_id: string;
  start_time: Date;
  end_time?: Date;
  status: 'active' | 'ended';
  metadata?: Record<string, any>;
}

export interface Transcript {
  id: string;
  conversation_id: string;
  speaker: 'agent' | 'caller';
  text: string;
  timestamp: Date;
  is_final: boolean;
}

export interface AIRecommendation {
  id: string;
  conversation_id: string;
  heading: string;
  suggestion: string;
  model_used: 'haiku' | 'sonnet';
  latency_ms: number;
  reasoning?: string;
  cached_tokens?: number;
  input_tokens?: number;
  output_tokens?: number;
  created_at: Date;
}

export async function createConversation(agentId: string): Promise<string> {
  const pool = getPgPool();
  try {
    const result = await pool.query(
      'INSERT INTO conversations (agent_id, start_time, status) VALUES ($1, NOW(), $2) RETURNING id',
      [agentId, 'active']
    );
    const conversationId = result.rows[0].id;
    console.log(`[PostgreSQL] Conversation created: ${conversationId}`);
    return conversationId;
  } catch (error) {
    console.error('[PostgreSQL] Error creating conversation:', error);
    throw error;
  }
}

export async function endConversation(conversationId: string): Promise<void> {
  const pool = getPgPool();
  try {
    await pool.query(
      'UPDATE conversations SET end_time = NOW(), status = $1 WHERE id = $2',
      ['ended', conversationId]
    );
    console.log(`[PostgreSQL] Conversation ended: ${conversationId}`);
  } catch (error) {
    console.error('[PostgreSQL] Error ending conversation:', error);
    throw error;
  }
}

export async function saveTranscript(transcript: Omit<Transcript, 'id'>): Promise<void> {
  const pool = getPgPool();
  try {
    await pool.query(
      'INSERT INTO transcripts (conversation_id, speaker, text, timestamp, is_final) VALUES ($1, $2, $3, $4, $5)',
      [transcript.conversation_id, transcript.speaker, transcript.text, transcript.timestamp, transcript.is_final]
    );
    console.log(`[PostgreSQL] Transcript saved for conversation: ${transcript.conversation_id}`);
  } catch (error) {
    console.error('[PostgreSQL] Error saving transcript:', error);
    throw error;
  }
}

export async function getRecentTranscripts(conversationId: string, limit: number = 10): Promise<Transcript[]> {
  const pool = getPgPool();
  try {
    const result = await pool.query(
      'SELECT * FROM transcripts WHERE conversation_id = $1 ORDER BY timestamp DESC LIMIT $2',
      [conversationId, limit]
    );
    return result.rows;
  } catch (error) {
    console.error('[PostgreSQL] Error getting transcripts:', error);
    return [];
  }
}

export async function getTranscriptCount(conversationId: string): Promise<number> {
  const pool = getPgPool();
  try {
    const result = await pool.query(
      'SELECT COUNT(*) as count FROM transcripts WHERE conversation_id = $1',
      [conversationId]
    );
    return parseInt(result.rows[0].count);
  } catch (error) {
    console.error('[PostgreSQL] Error getting transcript count:', error);
    return 0;
  }
}

export async function saveAIRecommendation(recommendation: Omit<AIRecommendation, 'id' | 'created_at'>): Promise<void> {
  const pool = getPgPool();
  try {
    await pool.query(
      `INSERT INTO ai_recommendations
       (conversation_id, heading, suggestion, model_used, latency_ms, reasoning, cached_tokens, input_tokens, output_tokens)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
      [
        recommendation.conversation_id,
        recommendation.heading,
        recommendation.suggestion,
        recommendation.model_used,
        recommendation.latency_ms,
        recommendation.reasoning,
        recommendation.cached_tokens,
        recommendation.input_tokens,
        recommendation.output_tokens
      ]
    );
    console.log(`[PostgreSQL] AI recommendation saved for conversation: ${recommendation.conversation_id}`);
  } catch (error) {
    console.error('[PostgreSQL] Error saving AI recommendation:', error);
    throw error;
  }
}

export async function getConversationSummary(conversationId: string): Promise<string> {
  const pool = getPgPool();
  try {
    const result = await pool.query(
      'SELECT summary FROM conversation_summaries WHERE conversation_id = $1 ORDER BY created_at DESC LIMIT 1',
      [conversationId]
    );
    return result.rows[0]?.summary || '';
  } catch (error) {
    console.error('[PostgreSQL] Error getting conversation summary:', error);
    return '';
  }
}

// Cleanup on Lambda exit
export async function closePgPool(): Promise<void> {
  if (pgPool) {
    await pgPool.end();
    pgPool = null;
    console.log('[PostgreSQL] Connection pool closed');
  }
}
